import { reactive } from "vue";
import { createAuth0Client } from "@auth0/auth0-spa-js";
/** Define a default action to perform after authentication */
const DEFAULT_REDIRECT_CALLBACK = () =>
  window.history.replaceState({}, document.title, window.location.pathname);
let instance;
/** Returns the current instance of the SDK */
export const getInstance = () => instance;
/** Creates an instance of the Auth0 SDK. If one has already been created, it returns that instance */
export const useAuth0 = ({
  onRedirectCallback = DEFAULT_REDIRECT_CALLBACK,
  redirectUri = window.location.origin,
  ...options
}) => {
  if (instance) return instance;
  // The 'instance' is a reactive object (replaces Vue 2's new Vue() pattern)
  instance = reactive({
    loading: true,
    isAuthenticated: false,
    user: {},
    auth0Client: null,
    popupOpen: false,
    error: null,
    /** Authenticates the user using a popup window */
    async loginWithPopup(options, config) {
      this.popupOpen = true;
      try {
        await this.auth0Client.loginWithPopup(options, config);
      } catch (e) {
        // eslint-disable-next-line
        console.error(e);
      } finally {
        this.popupOpen = false;
      }
      this.user = await this.auth0Client.getUser();
      this.isAuthenticated = true;
    },
    /** Handles the callback when logging in using a redirect */
    async handleRedirectCallback() {
      this.loading = true;
      try {
        await this.auth0Client.handleRedirectCallback();
        this.user = await this.auth0Client.getUser();
        this.isAuthenticated = true;
      } catch (e) {
        this.error = e;
      } finally {
        this.loading = false;
      }
    },
    /** Authenticates the user using the redirect method */
    loginWithRedirect(o) {
      return this.auth0Client.loginWithRedirect(o);
    },
    /** Returns all the claims present in the ID token */
    getIdTokenClaims(o) {
      return this.auth0Client.getIdTokenClaims(o);
    },
    /** Returns the access token. If the token is invalid or missing, a new one is retrieved */
    getTokenSilently(o) {
      return this.auth0Client.getTokenSilently(o);
    },
    /** Gets the access token using a popup window */
    getTokenWithPopup(o) {
      return this.auth0Client.getTokenWithPopup(o);
    },
    /** Logs the user out and removes their session on the authorization server */
    logout(o) {
      return this.auth0Client.logout(o);
    }
  });

  // Initialize the SDK client (was previously in Vue 2's created() lifecycle)
  (async () => {
    instance.auth0Client = await createAuth0Client({
      ...options,
      client_id: options.clientId,
      redirect_uri: redirectUri
    });
    try {
      // If the user is returning to the app after authentication..
      if (
        window.location.search.includes("code=") &&
        window.location.search.includes("state=")
      ) {
        // handle the redirect and retrieve tokens
        const { appState } = await instance.auth0Client.handleRedirectCallback();
        // Notify subscribers that the redirect callback has happened, passing the appState
        // (useful for retrieving any pre-authentication state)
        onRedirectCallback(appState);
      }
    } catch (e) {
      instance.error = e;
    } finally {
      // Initialize our internal authentication state
      instance.isAuthenticated = await instance.auth0Client.isAuthenticated();
      instance.user = await instance.auth0Client.getUser();
      instance.loading = false;
    }
  })();

  return instance;
};
// Create a simple Vue plugin to expose the wrapper object throughout the application
export const Auth0Plugin = {
  install(app, options) {
    app.config.globalProperties.$auth = useAuth0(options);
  }
};